    pub fn parse(s: []const u8) ?Timezone {
        return std.meta.stringToEnum(Timezone, s) orelse old_timezones.get(s);
    }

    pub const from_windows_name = if (builtin.os.tag == .windows)
        _from_windows_name
    else
        @compileError("from_windows_name is only available on Windows");

    fn _from_windows_name(s: []const u8, region: ?Region) ?Timezone {
        for (windows_timezones) |entry| {
            if (std.mem.eql(u8, s, entry.name)) {
                if (region) |r| {
                    for (entry.overrides) |override| {
                        if (r == override.region) {
                            return override.mapping;
                        }
                    }
                }
                return entry.mapping;
            }
        }
        return null;
    }
